Вот полный код программы с учётом всех ваших требований. Он реализует многоэтапный сценарий с возможностью внешней остановки через флаг `isBrain`.

### Схема подключения
*   **Grove LED Bar**: DATA → Пин 2, CLK → Пин 3, VCC → 5V, GND → GND
*   **Сервопривод FS5103B**: Оранжевый (Signal) → Пин 9, Красный (VCC) → 5V, Коричневый (GND) → GND

### Код программы

```cpp
#include <Grove_LED_Bar.h>
#include <Servo.h>

Grove_LED_Bar bar(2, 3, 1);
Servo servo;

// === НАСТРОЙКИ ВРЕМЕНИ ===
const unsigned long BLINK_DURATION = 5000;    // 5 сек мигания
const unsigned long COUNTDOWN_1 = 30000;      // 30 сек обратный отсчет
const unsigned long COUNTDOWN_2 = 60000;      // 60 сек с серво
const int SERVO_START = 0;                    // Начальный угол
const int SERVO_END = 90;                     // Конечный угол

// === ФЛАГИ ===
bool isBrain = true;       // Глобальный флаг разрешения работы
bool isDone = false;       // Флаг полного завершения цикла

// === СОСТОЯНИЯ ===
enum State { BLINK, COUNT1, WAIT, COUNT2, FINISH };
State currentState = BLINK;

// === ПЕРЕМЕННЫЕ ===
unsigned long phaseStart;
int blinkCount = 0;
int servoPos = SERVO_START;

void setup() {
  bar.begin();
  bar.setLevel(0);
  servo.attach(9);
  servo.write(servoPos);
  phaseStart = millis();
}

void loop() {
  // === ГЛОБАЛЬНАЯ ПРОВЕРКА ===
  if (!isBrain) {
    resetAll();
    return;
  }

  if (isDone) return;

  unsigned long elapsed = millis() - phaseStart;

  switch (currentState) {

    case BLINK:
      if (elapsed >= BLINK_DURATION) {
        currentState = COUNT1;
        phaseStart = millis();
        bar.setLevel(10);
      } else {
        bar.setLevel(10);
        delay(250);
        bar.setLevel(0);
        delay(250);
      }
      break;

    case COUNT1:
      if (elapsed >= COUNTDOWN_1) {
        currentState = WAIT;
        bar.setLevel(0);
      } else {
        int level = 10 - (elapsed * 10 / COUNTDOWN_1);
        if (level < 0) level = 0;
        bar.setLevel(level);
      }
      break;

    case WAIT:
      // Глобальный флаг ожидания (можно использовать для внешних событий)
      // Сейчас просто краткая пауза перед следующим этапом
      if (elapsed >= 1000) {
        currentState = COUNT2;
        phaseStart = millis();
        servoPos = SERVO_START;
        servo.write(servoPos);
      }
      break;

    case COUNT2:
      if (elapsed >= COUNTDOWN_2) {
        currentState = FINISH;
        isDone = true;
      } else {
        // Светодиоды
        int level = 10 - (elapsed * 10 / COUNTDOWN_2);
        if (level < 0) level = 0;
        bar.setLevel(level);

        // Серво (плавный поворот на 90 градусов за 60 сек)
        servoPos = map(elapsed, 0, COUNTDOWN_2, SERVO_START, SERVO_END);
        servo.write(servoPos);
      }
      break;

    case FINISH:
      bar.setLevel(0);
      break;
  }
}

// === СБРОС ПРИ isBrain = false ===
void resetAll() {
  bar.setLevel(0);
  servo.write(SERVO_START);
  currentState = BLINK;
  phaseStart = millis();
  blinkCount = 0;
  isDone = false;
  servoPos = SERVO_START;
}
```

### Как это работает

| Этап | Длительность | Светодиоды | Серво |
|------|--------------|------------|-------|
| **BLINK** | 5 сек | Мигают все 10 | На позиции 0° |
| **COUNT1** | 30 сек | Обратный отсчёт (10→0) | На позиции 0° |
| **WAIT** | 1 сек | Выключены | На позиции 0° |
| **COUNT2** | 60 сек | Обратный отсчёт (10→0) | Поворот 0°→90° |
| **FINISH** | ∞ | Выключены | На позиции 90° |

### Управление флагом `isBrain`

Чтобы управлять флагом `isBrain`, вы можете изменить его в коде или добавить кнопку:

**Вариант 1: Изменение в коде**
