// === ФУНКЦИИ ЭТАПОВ ===

void doBlinkPhase(unsigned long elapsed) {
  if (elapsed >= BLINK_DURATION) {
    currentState = COUNT1;
    phaseStart = millis();
    bar.setLevel(10);
  } else {
    bar.setLevel(10);
    delay(250);
    bar.setLevel(0);
    delay(250);
  }
}

void doCountdown1(unsigned long elapsed) {
  if (elapsed >= COUNTDOWN_1) {
    currentState = WAIT;
    phaseStart = millis();
    bar.setLevel(0);
  } else {
    bar.setLevel(calcLevel(elapsed, COUNTDOWN_1));
  }
}

void doWaitPhase(unsigned long elapsed) {
  if (elapsed >= 1000) {
    currentState = COUNT2;
    phaseStart = millis();
    servo.write(SERVO_START);
  }
}

void doCountdown2(unsigned long elapsed) {
  if (elapsed >= COUNTDOWN_2) {
    currentState = FINISH;
    isDone = true;
    bar.setLevel(0);           // ← ФИКС: гасим светодиоды
    servo.write(SERVO_END);    // серво на финишной позиции
  } else {
    bar.setLevel(calcLevel(elapsed, COUNTDOWN_2));
    int pos = map(elapsed, 0, COUNTDOWN_2, SERVO_START, SERVO_END);
    servo.write(pos);
  }
}

void doFinishPhase() {
  bar.setLevel(0);             // ← ФИКС: гарантированно выключаем всё
}

// === ВСПОМОГАТЕЛЬНЫЕ ФУНКЦИИ ===

int calcLevel(unsigned long elapsed, unsigned long duration) {
  int level = 10 - (elapsed * 10 / duration);
  return (level < 0) ? 0 : level;
}

void resetAll() {
  bar.setLevel(0);
  servo.write(SERVO_START);
  currentState = BLINK;
  phaseStart = millis();
  isDone = false;
}
```

### Что исправлено и улучшено:

| Проблема | Решение |
|----------|---------|
| **Горит 1 светодиод в конце** | В `doFinishPhase()` и при переходе на `FINISH` явно вызывается `bar.setLevel(0)` |
| **Весь код в `loop()`** | Каждый этап вынесен в свою функцию: `doBlinkPhase()`, `doCountdown1()` и т.д. |
| **Повторяющийся код** | Формула уровня вынесена в `calcLevel()` |
| **Магические числа** | Все настройки (время, пины, углы) вынесены в `const` в начало файла |

### Структура программы:

```
loop()
 ├─ проверка isBrain → resetAll()
 ├─ проверка isDone → выход
 └─ switch (currentState)
     ├─ BLINK  → doBlinkPhase()    // 5 сек мигания
     ├─ COUNT1 → doCountdown1()    // 30 сек обратный отсчёт
     ├─ WAIT   → doWaitPhase()     // 1 сек пауза
     ├─ COUNT2 → doCountdown2()    // 60 сек + серво 0°→90°
     └─ FINISH → doFinishPhase()   // всё выключено
```

