static bool lastButtonState = HIGH;

bool buttonState = digitalRead(BUTTON_PIN);
if (lastButtonState == HIGH && buttonState == LOW) {
  isBrain = !isBrain;  // Переключить флаг
  delay(50);           // Антидребезг
}
lastButtonState = buttonState;

if (!isBrain) {
