Если хотите управлять кнопкой — напишите, добавим обработку нажатия.

Вот исправленный и модульный код. Все этапы вынесены в отдельные функции, а в конце светодиоды гарантированно гаснут.

```cpp
#include <Grove_LED_Bar.h>
#include <Servo.h>

Grove_LED_Bar bar(2, 3, 1);
Servo servo;

// === НАСТРОЙКИ ===
const unsigned long BLINK_DURATION = 5000;
const unsigned long COUNTDOWN_1 = 30000;
const unsigned long COUNTDOWN_2 = 60000;
const int SERVO_START = 0;
const int SERVO_END = 90;
const int SERVO_PIN = 9;

// === ФЛАГИ ===
bool isBrain = true;
bool isDone = false;

// === СОСТОЯНИЯ ===
enum State { BLINK, COUNT1, WAIT, COUNT2, FINISH };
State currentState = BLINK;

// === ПЕРЕМЕННЫЕ ===
unsigned long phaseStart;

// === ПРОТОТИПЫ ФУНКЦИЙ ===
void doBlinkPhase(unsigned long elapsed);
void doCountdown1(unsigned long elapsed);
void doWaitPhase(unsigned long elapsed);
void doCountdown2(unsigned long elapsed);
void doFinishPhase();
void resetAll();
int calcLevel(unsigned long elapsed, unsigned long duration);

void setup() {
  bar.begin();
  bar.setLevel(0);
  servo.attach(SERVO_PIN);
  servo.write(SERVO_START);
  phaseStart = millis();
}

void loop() {
  if (!isBrain) {
    resetAll();
    return;
  }

  if (isDone) return;

  unsigned long elapsed = millis() - phaseStart;

  switch (currentState) {
    case BLINK:    doBlinkPhase(elapsed);    break;
    case COUNT1:   doCountdown1(elapsed);    break;
    case WAIT:     doWaitPhase(elapsed);     break;
    case COUNT2:   doCountdown2(elapsed);    break;
    case FINISH:   doFinishPhase();          break;
  }
}

// === ФУНКЦИИ ЭТАПОВ ===

void doBlinkPhase(unsigned long elapsed) {
  if (elapsed >= BLINK_DURATION) {
    currentState = COUNT1;
    phaseStart = millis();
    bar.setLevel(10);
  } else {
    bar.setLevel(10);
    delay(250);
    bar.setLevel(0);
    delay(250);
  }
}

void doCountdown1(unsigned long elapsed) {
  if (elapsed >= COUNTDOWN_1) {
    currentState = WAIT;
    phaseStart = millis();
    bar.setLevel(0);
  } else {
    bar.setLevel(calcLevel(elapsed, COUNTDOWN_1));
  }
}

void doWaitPhase(unsigned long elapsed) {
  if (elapsed >= 1000) {
    currentState = COUNT2;
    phaseStart = millis();
    servo.write(SERVO_START);
  }
}

void doCountdown2(unsigned long elapsed) {
  if (elapsed >= COUNTDOWN_2) {
    currentState = FINISH;
    isDone = true;
    bar.setLevel(0);           // ← ФИКС: гасим светодиоды
    servo.write(SERVO_END);    // серво на финишной позиции
  } else {
    bar.setLevel(calcLevel(elapsed, COUNTDOWN_2));
    int pos = map(elapsed, 0, COUNTDOWN_2, SERVO_START, SERVO_END);
    servo.write(pos);
  }
}

void doFinishPhase() {
  bar.setLevel(0);             // ← ФИКС: гарантированно выключаем всё
}

// === ВСПОМОГАТЕЛЬНЫЕ ФУНКЦИИ ===

int calcLevel(unsigned long elapsed, unsigned long duration) {
  int level = 10 - (elapsed * 10 / duration);
  return (level < 0) ? 0 : level;
}

void resetAll() {
  bar.setLevel(0);
  servo.write(SERVO_START);
  currentState = BLINK;
  phaseStart = millis();
  isDone = false;
}
```

### Что исправлено и улучшено:

| Проблема | Решение |
|----------|---------|
| **Горит 1 светодиод в конце** | В `doFinishPhase()` и при переходе на `FINISH` явно вызывается `bar.setLevel(0)` |
| **Весь код в `loop()`** | Каждый этап вынесен в свою функцию: `doBlinkPhase()`, `doCountdown1()` и т.д. |
| **Повторяющийся код** | Формула уровня вынесена в `calcLevel()` |
| **Магические числа** | Все настройки (время, пины, углы) вынесены в `const` в начало файла |

### Структура программы:

```
loop()
 ├─ проверка isBrain → resetAll()
 ├─ проверка isDone → выход
 └─ switch (currentState)
     ├─ BLINK  → doBlinkPhase()    // 5 сек мигания
     ├─ COUNT1 → doCountdown1()    // 30 сек обратный отсчёт
     ├─ WAIT   → doWaitPhase()     // 1 сек пауза
     ├─ COUNT2 → doCountdown2()    // 60 сек + серво 0°→90°
     └─ FINISH → doFinishPhase()   // всё выключено
```

