### Обновлённый код с функцией переливания цветов

```cpp
#include <Grove_LED_Bar.h>
#include <Servo.h>

Grove_LED_Bar bar(2, 3, 1);
Servo servo;

// === НАСТРОЙКИ ===
const unsigned long BLINK_DURATION = 5000;
const unsigned long COUNTDOWN_1 = 30000;
const unsigned long COUNTDOWN_2 = 60000;
const int SERVO_START = 0;
const int SERVO_END = 90;
const int SERVO_PIN = 9;

// === ПИНЫ RGB (PWM-пины на Mega: 2-13, 44-46) ===
const int RGB_R = 5;
const int RGB_G = 6;
const int RGB_B = 7;

// === ФЛАГИ ===
bool isBrain = true;
bool isDone = false;

// === СОСТОЯНИЯ ===
enum State { BLINK, COUNT1, WAIT, COUNT2, FINISH };
State currentState = BLINK;

// === ПЕРЕМЕННЫЕ ===
unsigned long phaseStart;
unsigned long rainbowStart;  // для анимации в FINISH

// === ПРОТОТИПЫ ===
void doBlinkPhase(unsigned long elapsed);
void doCountdown1(unsigned long elapsed);
void doWaitPhase(unsigned long elapsed);
void doCountdown2(unsigned long elapsed);
void doFinishPhase();
void resetAll();
int calcLevel(unsigned long elapsed, unsigned long duration);
void rainbowStep();
void setRGB(byte r, byte g, byte b);

void setup() {
  bar.begin();
  bar.setLevel(0);
  servo.attach(SERVO_PIN);
  servo.write(SERVO_START);

  // Настройка пинов RGB
  pinMode(RGB_R, OUTPUT);
  pinMode(RGB_G, OUTPUT);
  pinMode(RGB_B, OUTPUT);
  setRGB(0, 0, 0);

  phaseStart = millis();
  rainbowStart = 0;
}

void loop() {
  if (!isBrain) {
    resetAll();
    return;
  }

  if (isDone) return;

  unsigned long elapsed = millis() - phaseStart;

  switch (currentState) {
    case BLINK:    doBlinkPhase(elapsed);    break;
    case COUNT1:   doCountdown1(elapsed);    break;
    case WAIT:     doWaitPhase(elapsed);     break;
    case COUNT2:   doCountdown2(elapsed);    break;
    case FINISH:   doFinishPhase();          break;
  }
}

// === ФУНКЦИИ ЭТАПОВ ===

void doBlinkPhase(unsigned long elapsed) {
  if (elapsed >= BLINK_DURATION) {
    currentState = COUNT1;
    phaseStart = millis();
    bar.setLevel(10);
  } else {
    bar.setLevel(10);
    delay(250);
    bar.setLevel(0);
    delay(250);
  }
}

void doCountdown1(unsigned long elapsed) {
  if (elapsed >= COUNTDOWN_1) {
    currentState = WAIT;
    phaseStart = millis();
    bar.setLevel(0);
  } else {
    bar.setLevel(calcLevel(elapsed, COUNTDOWN_1));
  }
}

void doWaitPhase(unsigned long elapsed) {
  if (elapsed >= 1000) {
    currentState = COUNT2;
    phaseStart = millis();
    servo.write(SERVO_START);
  }
}

void doCountdown2(unsigned long elapsed) {
  if (elapsed >= COUNTDOWN_2) {
    currentState = FINISH;
    isDone = true;
    rainbowStart = millis();  // запускаем анимацию
    bar.setLevel(0);
    servo.write(SERVO_END);
  } else {
    bar.setLevel(calcLevel(elapsed, COUNTDOWN_2));
    int pos = map(elapsed, 0, COUNTDOWN_2, SERVO_START, SERVO_END);
    servo.write(pos);
  }
}

void doFinishPhase() {
  bar.setLevel(0);
  rainbowStep();  // ← анимация переливания цветов
}

// === ВСПОМОГАТЕЛЬНЫЕ ФУНКЦИИ ===

int calcLevel(unsigned long elapsed, unsigned long duration) {
  int level = 10 - (elapsed * 10 / duration);
  return (level < 0) ? 0 : level;
}

// Установка цвета RGB (0-255 для каждого канала)
void setRGB(byte r, byte g, byte b) {
  analogWrite(RGB_R, r);
  analogWrite(RGB_G, g);
  analogWrite(RGB_B, b);
}

// Плавное переливание цветов (радуга)
void rainbowStep() {
  unsigned long t = millis() - rainbowStart;

  // HSV → RGB конвертация для плавного цикла
  float hue = fmod(t * 0.05, 360.0);  // скорость смены цвета
  float s = 1.0, v = 1.0;

  int hi = floor(hue / 60) % 6;
  float f = hue / 60 - floor(hue / 60);
  float p = v * (1 - s);
  float q = v * (1 - f * s);
  float t_ = v * (1 - (1 - f) * s);

  byte r, g, b;
  switch (hi) {
    case 0: r = v*255; g = t_*255; b = p*255; break;
    case 1: r = q*255; g = v*255; b = p*255; break;
    case 2: r = p*255; g = v*255; b = t_*255; break;
    case 3: r = p*255; g = q*255; b = v*255; break;
    case 4: r = t_*255; g = p*255; b = v*255; break;
    default: r = v*255; g = p*255; b = q*255; break;
  }

  setRGB(r, g, b);
}

void resetAll() {
  bar.setLevel(0);
  setRGB(0, 0, 0);           // гасим RGB
  servo.write(SERVO_START);
  currentState = BLINK;
  phaseStart = millis();
  rainbowStart = 0;
  isDone = false;
}
```

### Как работает анимация:
| Функция | Что делает |
|---------|-----------|
| `setRGB(r, g, b)` | Устанавливает цвет через PWM (0–255) |
| `rainbowStep()` | Конвертирует время в оттенок (HSV→RGB) и плавно меняет цвет |
| `fmod(t * 0.05, 360)` | Контролирует скорость цикла: меньше множитель → медленнее смена |

### Если цвета инвертированы (Common Anode):
Замените функцию `setRGB` на:
```cpp
void setRGB(byte r, byte g, byte b) {
  analogWrite(RGB_R, 255 - r);  // инверсия для общего анода
  analogWrite(RGB_G, 255 - g);
  analogWrite(RGB_B, 255 - b);
}
```

### Настройка скорости анимации:
```cpp
// В rainbowStep(), строка с hue:
float hue = fmod(t * 0.05, 360.0);  // 0.05 = медленно
// Попробуйте: 0.1 = быстрее, 0.02 = очень медленно
```

### Проверка перед запуском:
1.  Убедитесь, что пины 5, 6, 7 поддерживают PWM (на Mega — все цифровые 2–13).
2.  Проверьте тип светодиода (Common Cathode/Anode).
3.  Не забудьте резисторы 220Ω на каждом цветовом канале.

Теперь при завершении таймера светодиоды погаснут, серво встанет на 90°, а RGB начнёт плавно переливаться всеми цветами радуги 🌈

Понял, убираем RGB. Вот чистый, модульный код без светодиода — с исправленным финалом и всеми этапами.

```cpp
#include <Grove_LED_Bar.h>
#include <Servo.h>

Grove_LED_Bar bar(2, 3, 1);
Servo servo;

// === НАСТРОЙКИ ===
const unsigned long BLINK_DURATION = 5000;
const unsigned long COUNTDOWN_1 = 30000;
const unsigned long COUNTDOWN_2 = 60000;
const int SERVO_START = 0;
const int SERVO_END = 90;
const int SERVO_PIN = 9;

// === ФЛАГИ ===
bool isBrain = true;
bool isDone = false;

// === СОСТОЯНИЯ ===
enum State { BLINK, COUNT1, WAIT, COUNT2, FINISH };
State currentState = BLINK;

// === ПЕРЕМЕННЫЕ ===
unsigned long phaseStart;

// === ПРОТОТИПЫ ===
void doBlinkPhase(unsigned long elapsed);
void doCountdown1(unsigned long elapsed);
void doWaitPhase(unsigned long elapsed);
void doCountdown2(unsigned long elapsed);
void doFinishPhase();
void resetAll();
int calcLevel(unsigned long elapsed, unsigned long duration);

void setup() {
  bar.begin();
  bar.setLevel(0);
  servo.attach(SERVO_PIN);
  servo.write(SERVO_START);
  phaseStart = millis();
}

void loop() {
  if (!isBrain) {
    resetAll();
    return;
  }

  if (isDone) return;

  unsigned long elapsed = millis() - phaseStart;

  switch (currentState) {
    case BLINK:    doBlinkPhase(elapsed);    break;
    case COUNT1:   doCountdown1(elapsed);    break;
    case WAIT:     doWaitPhase(elapsed);     break;
    case COUNT2:   doCountdown2(elapsed);    break;
    case FINISH:   doFinishPhase();          break;
  }
}

// === ФУНКЦИИ ЭТАПОВ ===

void doBlinkPhase(unsigned long elapsed) {
  if (elapsed >= BLINK_DURATION) {
    currentState = COUNT1;
    phaseStart = millis();
    bar.setLevel(10);
  } else {
    bar.setLevel(10);
    delay(250);
    bar.setLevel(0);
    delay(250);
  }
}

void doCountdown1(unsigned long elapsed) {
  if (elapsed >= COUNTDOWN_1) {
    currentState = WAIT;
    phaseStart = millis();
    bar.setLevel(0);
  } else {
    bar.setLevel(calcLevel(elapsed, COUNTDOWN_1));
  }
}

void doWaitPhase(unsigned long elapsed) {
  if (elapsed >= 1000) {
    currentState = COUNT2;
    phaseStart = millis();
    servo.write(SERVO_START);
  }
}

void doCountdown2(unsigned long elapsed) {
  if (elapsed >= COUNTDOWN_2) {
    currentState = FINISH;
    isDone = true;
    bar.setLevel(0);
    servo.write(SERVO_END);
  } else {
    bar.setLevel(calcLevel(elapsed, COUNTDOWN_2));
    int pos = map(elapsed, 0, COUNTDOWN_2, SERVO_START, SERVO_END);
    servo.write(pos);
  }
}

// === ФИКС: финал — всё выключено ===
void doFinishPhase() {
  bar.setLevel(0);
  // Серво остаётся на 90°, светодиоды выключены
}

// === ВСПОМОГАТЕЛЬНЫЕ ФУНКЦИИ ===

int calcLevel(unsigned long elapsed, unsigned long duration) {
  int level = 10 - (elapsed * 10 / duration);
  return (level < 0) ? 0 : level;
}

void resetAll() {
  bar.setLevel(0);
  servo.write(SERVO_START);
  currentState = BLINK;
  phaseStart = millis();
  isDone = false;
}
```

### Сценарий работы:

| Этап | Длительность | Светодиоды | Серво |
|------|--------------|------------|-------|
| **BLINK** | 5 сек | Мигают все 10 | 0° |
| **COUNT1** | 30 сек | 10 → 0 (обратный отсчёт) | 0° |
| **WAIT** | 1 сек | Выключены | 0° |
| **COUNT2** | 60 сек | 10 → 0 | 0° → 90° (плавно) |
| **FINISH** | ∞ | **Выключены** ✅ | 90° |

### Управление:
```cpp
// Остановить и сбросить в любое время:
isBrain = false;

// Запустить заново:
isBrain = true;
```

### Если нужно добавить кнопку переключения `isBrain`:
```cpp
// В setup():
pinMode(4, INPUT_PULLUP);  // кнопка между пином 4 и GND

// В начало loop():
static bool lastBtn = HIGH;
bool curBtn = digitalRead(4);
if (lastBtn == HIGH && curBtn == LOW) {
  isBrain = !isBrain;
  delay(50);  // антидребезг
}
lastBtn = curBtn;
```

Код полностью готов: модульный, без дубликатов, с гарантированно выключенными светодиодами в конце. Если нужно добавить зуммер, дисплей или другие события — просто создайте новую функцию и добавьте кейс в `switch`.

