const unsigned long TRAINING_TIME = 180000;      // 3 минуты тренинг
const unsigned long EMG_SMOOTH_MS = 500;         // окно сглаживания ЭМГ
const unsigned long SEND_INTERVAL = 100;         // отправка на ПК каждые 100 мс

